  ('aboriginal-014e6a52-moex-00171', 'aboriginal-014e6a52', 'aboriginal-014e6a52-moex-110-6ed013db', 'sub-aboriginal-014e6a52-03', NULL, 'single_choice', '下列關於原住民族基本法之規定的敘述，何者錯誤？', '["政府為辦理原住民族土地之調查及處理，應設置原住民族土地調查及處理委員會；其組織及相關事 務，另以法律定之", "原住民族或原住民所有、使用之土地、海域，其回復、取得、處分、計畫、管理及利用等事項，另 以法律定之", "政府應依原住民族意願，保障原住民族之平等地位及自主發展，實行原住民族自治；其相關事項， 另以法律定之", "主管機關應於本法施行後30年內，依本法之原則修正、制定或廢止相關法令"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "512", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "測量製圖"}'::jsonb, NULL),
  ('aboriginal-014e6a52-moex-00172', 'aboriginal-014e6a52', 'aboriginal-014e6a52-moex-110-6ed013db', 'sub-aboriginal-014e6a52-03', NULL, 'single_choice', '根據山坡地保育利用條例第37條，原住民取得原住民保留地所有權，如有移轉，以原住民為限，但 有特定情形者，得由政府承受私有原住民保留地，以下何者不屬於得由政府承受私有原住民保留地之 特定情形？', '["興辦土地徵收條例第3條、第4條第1項規定之各款事業及所有權人依該條例第8條規定申請一併 徵收", "經中央原住民族主管機關審認符合災害之預防、災害發生時之應變及災後之復原重建用地需求", "稅捐稽徵機關受理以原住民保留地抵繳增值稅", "因公法金錢給付義務之執行事件未能拍定原住民保留地"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "512", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "測量製圖"}'::jsonb, NULL),
  ('aboriginal-014e6a52-moex-00173', 'aboriginal-014e6a52', 'aboriginal-014e6a52-moex-110-6ed013db', 'sub-aboriginal-014e6a52-03', NULL, 'single_choice', '原住民保留地開發管理辦法第27條中規定，第23條至第25條之原住民保留地承租人有特定情形者， 應終止租約收回土地，其所投資之各項設施不予補償。以下所述何者不屬這些特定情形？', '["經原住民保留地土地權利審查委員會提案並通過終止租約者", "違反計畫使用者", "轉租或由他人頂替者", "未依開發或興辦計畫開發或興辦，且未報經核准變更計畫或展延開發、興辦期限者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "512", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "測量製圖"}'::jsonb, NULL),
  ('aboriginal-014e6a52-moex-00174', 'aboriginal-014e6a52', 'aboriginal-014e6a52-moex-110-6ed013db', 'sub-aboriginal-014e6a52-03', NULL, 'single_choice', '根據人體研究法第15條，以研究原住民族為目的者，除依第12條至第14條規定外，並應諮詢、取 得各該原住民族之同意，而根據原住民族委員會所訂定之人體研究計畫諮詢取得原住民族同意與約定 商業利益及其應用辦法之定義，「以研究原住民族為目的者」不包含以下那一項？', '["以原住民族或部落為研究內容", "研究檢體之採集、研究資料之搜集及分析涉及原住民族或部落", "研究結果之解釋涉及原住民族或部落", "研究團隊之成員三分之一以上為原住民"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "512", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "測量製圖"}'::jsonb, NULL),
  ('aboriginal-014e6a52-moex-00175', 'aboriginal-014e6a52', 'aboriginal-014e6a52-moex-110-6ed013db', 'sub-aboriginal-014e6a52-03', NULL, 'single_choice', '根據推動原住民族法律服務要點第5點，具「依申請人之陳述及所提資料，顯無理由」，或是「訴訟 所可能獲得之利益，小於律師酬金」之情形者，不予服務。但如涉及下列那些情形者，仍得予提供法 律服務？', '["原住民族傳統慣習、原住民族基本權利與國家法令、司法程序衝突", "同一申請人自准予扶助起1年內，依第3點第4款准予扶助達3次", "申請人為其住所地直轄市、縣（市）主管機關審核認定之社會救助法中低收入戶", "申請人具公務人員身分，且涉及公職人員選舉罷免事件相關之民事訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:44+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "512", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "測量製圖"}'::jsonb, NULL),
